// ==========================
// LOGIC SUMMARY / CHANGE NOTES
// ==========================
// Flow version rule:
// - the Node-RED tab label in `flows.json` uses `d#<n>` as the deployed flow version marker
// - increment that marker every time `flows.json` changes so the active Node-RED flow version is visible
// - keep this file, the embedded controller function, and the tab version rule synchronized
// Current behavior implemented after iterative tuning:
// 1. This function now has 4 outputs:
//    - output 1 -> DVCC charge current limit (A)
//    - output 2 -> ESS grid setpoint (W)
//    - output 3 -> VE.Bus AC input current limit (A)
//    - output 4 -> VRM notification message
// 2. The function accepts multiple message types:
//    - `topic = battery-voltage` -> updates battery voltage state
//    - `topic = grid-power` -> updates measured grid import power in W
//      (preferred source: GX System GRID CT sensor, e.g. `/Ac/Grid/L1/Power`)
//    - `topic = ac-load-power` -> updates measured AC loads power in W
//      (source: GX System `/Ac/Consumption/L1/Power`)
//    - any other topic / inject -> recalculates outputs using stored state
// 3. Night charging uses hysteresis:
//    - ON again at 54.5V or lower
//    - OFF at 54.8V or higher
// 4. Morning charging uses hysteresis:
//    - ON below 53.5V
//    - OFF above 53.8V
// 5. Evening charging uses hysteresis:
//    - ON below 54.0V
//    - OFF above 54.4V
// 6. Base grid setpoint schedule:
//    - 2850W at night
//    - 1980W during the rest of the day
// 7. High-voltage protection for unknown external MPPT charging:
//    - start limiting when battery voltage rises above 55.4V
//    - release only after voltage drops back to 55.2V or lower
//    - taper grid setpoint smoothly down to a minimum of 200W by 55.6V
// 8. Hourly import Wh is tracked for display only:
//    - integrates positive grid import within the current clock hour
//    - shows accumulated Wh together with the actual accumulation start/end time in status
//    - does not change charge current, grid setpoint, or any other output
// 9. Solar prediction is connected to charging logic and affects only charging current:
//    - reads `flow.solarForecastToday`
//    - reduces morning/evening charging on sunny or cloudy forecast days
//    - does not change grid setpoint
// 10. Remaining average watts left in the current hour are shown for info only when
//    tracking for that hour started at the beginning of the hour.
// 11. Final grid setpoint is the minimum of:
//    - base schedule
//    - high-voltage limit
// 12. Grid setpoint reduction due to battery over-voltage is smoothed so the battery does not
//     see large sudden load changes.
// 13. VE.Bus Input 1 current limit is no longer controlled by this function.
// 14. A VRM notification is emitted when the grid setpoint changes.
// 15. `boostActive`, `activeWindow`, battery voltage, grid power, and display-only hourly Wh are
//     all stored in context.
// 16. `day-night.txt` and the embedded `func` in `flows.json` must always stay synchronized.
// 17. Increment the `d#<n>` tab version in `flows.json` every time the flow file changes.
// 18. AC loads hourly Wh is tracked for display only (same integration logic as grid import Wh).
// 19. Notifications are written to a daily file at `/data/grid-control-logs/grid-control-YYYY-MM-DD.log`.
//     Old log files are pruned automatically; files older than 45 days are deleted at midnight.

// ==========================
// INPUT / OUTPUT TOPICS
// ==========================
const BATTERY_TOPIC = "battery-voltage";
const GRID_TOPIC = "grid-power";
const AC_LOAD_TOPIC = "ac-load-power";

// ==========================
// CONSTANTS
// ==========================
const MAX_CHARGE_CURRENT = 25;

const SOLAR_FORECAST_MAX_AGE_HOURS = 18;
const SOLAR_FORECAST_ACTIVE_START_HOUR = 5;
const SOLAR_FORECAST_ACTIVE_END_HOUR = 21;
const SUNNY_MORNING_CHARGE_FACTOR = 0.25;
const SUNNY_EVENING_CHARGE_FACTOR = 0.5;
const CLOUDY_MORNING_CHARGE_FACTOR = 0.6;
const CLOUDY_EVENING_CHARGE_FACTOR = 0.8;

const DAY_BASE_GRID_SETPOINT = 1980;
const NIGHT_BASE_GRID_SETPOINT = 2850;
const DAY_HOURLY_BUDGET_W = 1980;
const NIGHT_HOURLY_BUDGET_W = 2850;

const NIGHT_ON_VOLTAGE = 54.5;
const NIGHT_OFF_VOLTAGE = 54.8;

const MORNING_ON_VOLTAGE = 53.5;
const MORNING_OFF_VOLTAGE = 53.8;

const EVENING_ON_VOLTAGE = 54.0;
const EVENING_OFF_VOLTAGE = 54.4;

const HIGH_VOLTAGE_LIMIT_START = 55.4;
const HIGH_VOLTAGE_LIMIT_RELEASE = 55.2;
const HIGH_VOLTAGE_LIMIT_FULL = 55.6;
const MIN_GRID_SETPOINT = 200;
const MAX_GRID_STEP_W = 100;

// ==========================
// TIME
// ==========================
const now = new Date();
const hour = now.getHours();
const minute = now.getMinutes();
const second = now.getSeconds();

// ==========================
// CONTEXT MEMORY
// ==========================
let boostActive = context.get("boostActive") || false;
const previousWindow = context.get("activeWindow") || "none";
let batteryVoltage = Number(context.get("batteryVoltage"));
const rawStoredGridPower = context.get("gridPowerW");
const hasGridPowerReading = rawStoredGridPower !== undefined && rawStoredGridPower !== null && Number.isFinite(Number(rawStoredGridPower));
const storedGridPowerW = hasGridPowerReading ? Math.max(0, Number(rawStoredGridPower)) : 0;
let gridPowerW = storedGridPowerW;
const rawStoredAcLoadPower = context.get("acLoadPowerW");
const hasAcLoadReading = rawStoredAcLoadPower !== undefined && rawStoredAcLoadPower !== null && Number.isFinite(Number(rawStoredAcLoadPower));
const storedAcLoadPowerW = hasAcLoadReading ? Math.max(0, Number(rawStoredAcLoadPower)) : 0;
let voltageLimitActive = context.get("voltageLimitActive") || false;
const previousGridSetpoint = Number(context.get("gridSetpoint"));
let hourBudget = context.get("hourBudget") || {
    hourKey: "",
    lastTs: 0,
    usedWh: 0,
    startTs: 0,
    fullHourCoverage: false
};
let acLoadBudget = context.get("acLoadBudget") || {
    hourKey: "",
    lastTs: 0,
    usedWh: 0,
    startTs: 0,
    fullHourCoverage: false
};

// ==========================
// HELPERS
// ==========================
function clamp(value, min, max) {
    return Math.min(Math.max(value, min), max);
}

function round1(value) {
    return Math.round(value * 10) / 10;
}

function getHourKey(date) {
    return [
        date.getFullYear(),
        String(date.getMonth() + 1).padStart(2, "0"),
        String(date.getDate()).padStart(2, "0")
    ].join("-") + " " + String(date.getHours()).padStart(2, "0");
}

function getHourStartTs(date) {
    return new Date(
        date.getFullYear(),
        date.getMonth(),
        date.getDate(),
        date.getHours(),
        0,
        0,
        0
    ).getTime();
}

function getDayKey(date) {
    return [
        date.getFullYear(),
        String(date.getMonth() + 1).padStart(2, "0"),
        String(date.getDate()).padStart(2, "0")
    ].join("-");
}

function formatTime(date) {
    return `${String(date.getHours()).padStart(2, "0")}:${String(date.getMinutes()).padStart(2, "0")}`;
}

function getSolarForecastSummary(date) {
    const rawForecast = flow.get("solarForecastToday");

    if (!rawForecast || typeof rawForecast !== "object") {
        return {
            valid: false,
            condition: "unknown",
            energyKWh: 0,
            peakKW: 0
        };
    }

    const updatedAt = new Date(rawForecast.updatedAt);
    const ageHours = Number.isFinite(updatedAt.getTime())
        ? (date.getTime() - updatedAt.getTime()) / 3600000
        : Number.POSITIVE_INFINITY;
    const sameDay = Number.isFinite(updatedAt.getTime())
        ? getDayKey(updatedAt) === getDayKey(date)
        : false;

    return {
        valid: sameDay && ageHours >= 0 && ageHours <= SOLAR_FORECAST_MAX_AGE_HOURS,
        condition: String(rawForecast.condition || "unknown").toLowerCase(),
        energyKWh: Number(rawForecast.energyKWh) || 0,
        peakKW: Number(rawForecast.peakKW) || 0
    };
}

function getSolarChargeControl(window, date) {
    const forecast = getSolarForecastSummary(date);
    const currentHour = date.getHours();
    const inForecastWindow =
        currentHour >= SOLAR_FORECAST_ACTIVE_START_HOUR &&
        currentHour < SOLAR_FORECAST_ACTIVE_END_HOUR;

    const result = {
        factor: 1,
        active: false,
        forecast
    };

    if (!forecast.valid || !inForecastWindow) {
        return result;
    }

    if (window === "MORNING") {
        if (forecast.condition === "sunny") {
            result.factor = SUNNY_MORNING_CHARGE_FACTOR;
        }
        else if (forecast.condition === "cloudy") {
            result.factor = CLOUDY_MORNING_CHARGE_FACTOR;
        }
    }
    else if (window === "EVENING") {
        if (forecast.condition === "sunny") {
            result.factor = SUNNY_EVENING_CHARGE_FACTOR;
        }
        else if (forecast.condition === "cloudy") {
            result.factor = CLOUDY_EVENING_CHARGE_FACTOR;
        }
    }

    result.active = result.factor < 1;
    return result;
}

function advanceHourBudget(state, date, importPowerW) {
    const nextState = {
        hourKey: state.hourKey || "",
        lastTs: Number(state.lastTs) || 0,
        usedWh: Number(state.usedWh) || 0,
        startTs: Number(state.startTs) || 0,
        fullHourCoverage: Boolean(state.fullHourCoverage)
    };

    const nowTs = date.getTime();
    const hourKey = getHourKey(date);
    const hourStartTs = getHourStartTs(date);

    if (!nextState.lastTs || nextState.hourKey !== hourKey || nextState.lastTs < hourStartTs) {
        nextState.hourKey = hourKey;
        nextState.lastTs = hourStartTs;
        nextState.usedWh = 0;
        nextState.startTs = date.getMinutes() === 0 ? hourStartTs : nowTs;
        nextState.fullHourCoverage = date.getMinutes() === 0;
    }

    if (nowTs > nextState.lastTs) {
        const deltaHours = (nowTs - nextState.lastTs) / 3600000;
        nextState.usedWh += Math.max(0, importPowerW) * deltaHours;
        nextState.lastTs = nowTs;
    }

    return nextState;
}

function smoothReduction(previousValue, targetValue, maxStep) {
    if (!Number.isFinite(previousValue)) {
        return targetValue;
    }

    if (targetValue < previousValue - maxStep) {
        return previousValue - maxStep;
    }

    if (targetValue > previousValue + maxStep) {
        return previousValue + maxStep;
    }

    return targetValue;
}

function buildNotification(window, gridSetpoint) {
    const parts = [
        `${window}`,
        `V=${batteryVoltage.toFixed(2)}V`,
        `Grid setpoint=${gridSetpoint}W`
    ];

    if (limitFlags.length > 0) {
        parts.push(`Limit=${limitFlags.join("+")}`);
    }

    return {
        topic: "vrm-notification",
        payload: parts.join(" | "),
        notification: {
            message: parts.join(" | "),
            level: "info",
            timestamp: now.toISOString()
        }
    };
}

function buildOutputs(chargeCurrent, gridSetpoint, hourlyLogMsg) {
    const notifyMsg =
        gridSetpoint !== previousGridSetpoint
            ? buildNotification(windowName, gridSetpoint)
            : null;

    return [
        {
            topic: "charge-current-limit",
            payload: chargeCurrent
        },
        {
            topic: "grid-setpoint",
            payload: gridSetpoint
        },
        {
            topic: "ac-input-current-limit",
            payload: null
        },
        notifyMsg,
        hourlyLogMsg || null
    ];
}

// ==========================
// UPDATE STORED INPUTS
// ==========================
const prevHourKey = hourBudget.hourKey;
const prevHourGridWh = Number(hourBudget.usedWh) || 0;
const prevHourAcWh = Number(acLoadBudget.usedWh) || 0;
hourBudget = advanceHourBudget(hourBudget, now, storedGridPowerW);
acLoadBudget = advanceHourBudget(acLoadBudget, now, storedAcLoadPowerW);
const hourRolledOver = prevHourKey && prevHourKey !== hourBudget.hourKey;

if (msg.topic === BATTERY_TOPIC) {
    const incomingVoltage = Number(msg.payload);

    if (Number.isFinite(incomingVoltage)) {
        batteryVoltage = incomingVoltage;
        context.set("batteryVoltage", batteryVoltage);
    }
}
else if (msg.topic === GRID_TOPIC) {
    const incomingGridPower = Number(msg.payload);

    if (Number.isFinite(incomingGridPower)) {
        gridPowerW = Math.max(0, incomingGridPower);
        context.set("gridPowerW", gridPowerW);
    }
}
else if (msg.topic === AC_LOAD_TOPIC) {
    const incomingAcLoadPower = Number(msg.payload);

    if (Number.isFinite(incomingAcLoadPower)) {
        context.set("acLoadPowerW", Math.max(0, incomingAcLoadPower));
    }
}

context.set("hourBudget", hourBudget);
context.set("acLoadBudget", acLoadBudget);

if (!Number.isFinite(batteryVoltage)) {
    node.status({
        fill: "grey",
        shape: "ring",
        text: "WAITING FOR BATTERY VOLTAGE"
    });
    return null;
}

// ==========================
// TIME WINDOWS
// ==========================
const nightWindow = (hour >= 22 || hour < 6);

const morningWindow =
    (hour > 6 && hour < 11) ||
    (hour === 6) ||
    (hour === 11 && minute <= 59);

const eveningWindow = hour >= 17;

const baseScheduleSetpoint = nightWindow ? NIGHT_BASE_GRID_SETPOINT : DAY_BASE_GRID_SETPOINT;
const hourlyBudgetLimit = nightWindow ? NIGHT_HOURLY_BUDGET_W : DAY_HOURLY_BUDGET_W;

// ==========================
// CHARGE CURRENT WINDOW LOGIC
// ==========================
let windowName = "OUTSIDE";
let baseChargeCurrent = 0;

if (nightWindow) {
    windowName = "NIGHT";

    if (previousWindow !== windowName) {
        boostActive = true;
    }

    if (boostActive && batteryVoltage >= NIGHT_OFF_VOLTAGE) {
        boostActive = false;
    }

    if (!boostActive && batteryVoltage <= NIGHT_ON_VOLTAGE) {
        boostActive = true;
    }

    baseChargeCurrent = boostActive ? MAX_CHARGE_CURRENT : 0;
}
else if (morningWindow) {
    windowName = "MORNING";

    if (previousWindow !== windowName) {
        boostActive = false;
    }

    if (!boostActive && batteryVoltage < MORNING_ON_VOLTAGE) {
        boostActive = true;
    }

    if (boostActive && batteryVoltage > MORNING_OFF_VOLTAGE) {
        boostActive = false;
    }

    baseChargeCurrent = boostActive ? MAX_CHARGE_CURRENT : 0;
}
else if (eveningWindow) {
    windowName = "EVENING";

    if (previousWindow !== windowName) {
        boostActive = false;
    }

    if (!boostActive && batteryVoltage < EVENING_ON_VOLTAGE) {
        boostActive = true;
    }

    if (boostActive && batteryVoltage > EVENING_OFF_VOLTAGE) {
        boostActive = false;
    }

    baseChargeCurrent = boostActive ? MAX_CHARGE_CURRENT : 0;
}
else {
    boostActive = false;
    baseChargeCurrent = 0;
}

const solarChargeControl = getSolarChargeControl(windowName, now);
const forecastAdjustedChargeCurrent = baseChargeCurrent > 0
    ? round1(baseChargeCurrent * solarChargeControl.factor)
    : 0;

// ==========================
// HIGH-VOLTAGE GRID SETPOINT LIMIT
// ==========================
if (!voltageLimitActive && batteryVoltage > HIGH_VOLTAGE_LIMIT_START) {
    voltageLimitActive = true;
}

if (voltageLimitActive && batteryVoltage <= HIGH_VOLTAGE_LIMIT_RELEASE) {
    voltageLimitActive = false;
}

let voltageLimitedSetpoint = baseScheduleSetpoint;

if (voltageLimitActive) {
    const taper = clamp(
        (HIGH_VOLTAGE_LIMIT_FULL - batteryVoltage) /
        (HIGH_VOLTAGE_LIMIT_FULL - HIGH_VOLTAGE_LIMIT_START),
        0,
        1
    );

    voltageLimitedSetpoint = Math.round(
        MIN_GRID_SETPOINT + (baseScheduleSetpoint - MIN_GRID_SETPOINT) * taper
    );
}

// Apply smoothing only to the voltage-based reduction so the battery does not see large jumps.
if (voltageLimitActive) {
    voltageLimitedSetpoint = Math.round(
        smoothReduction(
            previousGridSetpoint,
            voltageLimitedSetpoint,
            MAX_GRID_STEP_W
        )
    );
}

// ==========================
// FINAL OUTPUTS
// ==========================
const finalGridSetpoint = Math.max(
    0,
    Math.round(
        Math.min(
            baseScheduleSetpoint,
            voltageLimitedSetpoint
        )
    )
);

const currentRatio = baseScheduleSetpoint > 0
    ? clamp(finalGridSetpoint / baseScheduleSetpoint, 0, 1)
    : 0;

const finalChargeCurrent = forecastAdjustedChargeCurrent > 0
    ? round1(forecastAdjustedChargeCurrent * currentRatio)
    : 0;
const usedWh = hourBudget.usedWh || 0;
const acUsedWh = acLoadBudget.usedWh || 0;
const usedEnergyStartLabel = formatTime(new Date(hourBudget.startTs || now.getTime()));
const usedEnergyEndLabel = formatTime(now);
const secondsIntoHour = minute * 60 + second;
const secondsLeftInHour = Math.max(1, 3600 - secondsIntoHour);
const hoursLeftInHour = secondsLeftInHour / 3600;
const remainingWh = clamp(hourlyBudgetLimit - usedWh, 0, hourlyBudgetLimit);
const remainingAverageW = Math.round(remainingWh / hoursLeftInHour);
const remainingAverageText = hourBudget.fullHourCoverage
    ? ` | ${remainingAverageW}W left`
    : "";

context.set("boostActive", boostActive);
context.set("activeWindow", windowName);
context.set("voltageLimitActive", voltageLimitActive);
context.set("gridSetpoint", finalGridSetpoint);

// ==========================
// STATUS
// ==========================
const limitFlags = [];

if (voltageLimitActive && finalGridSetpoint <= voltageLimitedSetpoint) {
    limitFlags.push("HV");
}

if (solarChargeControl.active) {
    limitFlags.push(`SOL:${solarChargeControl.forecast.condition.toUpperCase()}`);
}

let fill = "grey";

if (windowName === "NIGHT") {
    fill = finalChargeCurrent > 0 ? "blue" : "yellow";
}
else if (windowName === "MORNING" || windowName === "EVENING") {
    fill = finalChargeCurrent > 0 ? "green" : "yellow";
}

const flagsText = limitFlags.length > 0 ? ` | ${limitFlags.join("+")}` : "";
const forecastText = solarChargeControl.forecast.valid
    ? ` | FC=${solarChargeControl.forecast.condition} x${solarChargeControl.factor}`
    : "";

node.status({
    fill,
    shape: finalChargeCurrent > 0 || finalGridSetpoint > 0 ? "dot" : "ring",
    text: `${windowName} | V=${batteryVoltage.toFixed(2)}V | ${finalChargeCurrent}A | ${finalGridSetpoint}W | Grid ${usedEnergyStartLabel}-${usedEnergyEndLabel} ${Math.round(usedWh)}Wh | AC ${Math.round(acUsedWh)}Wh${remainingAverageText}${forecastText}${flagsText}`
});

const hourlyLogMsg = hourRolledOver
    ? { topic: "hourly-energy", payload: { hourKey: prevHourKey, gridWh: Math.round(prevHourGridWh), acWh: Math.round(prevHourAcWh) } }
    : null;

return buildOutputs(
    finalChargeCurrent,
    finalGridSetpoint,
    hourlyLogMsg
);

const defaultTitle = "Day / Night Grid Control";

function normalizeType(value) {
    if (value === 0 || value === "0" || value === "warning") {
        return 0;
    }

    if (value === 1 || value === "1" || value === "alarm") {
        return 1;
    }

    return 2;
}

const title = msg.title || (msg.notification && msg.notification.title) || defaultTitle;
const rawType = msg.type !== undefined
    ? msg.type
    : (msg.notification && (msg.notification.type !== undefined ? msg.notification.type : msg.notification.level));
const rawMessage = (msg.notification && msg.notification.message) || msg.payload;

if (rawMessage === undefined || rawMessage === null || rawMessage === "") {
    return null;
}

const safeTitle = String(title)
    .replace(/\t/g, " ")
    .replace(/[\r\n]/g, " ")
    .trim()
    .slice(0, 100);

const safeMessage = String(rawMessage)
    .replace(/\t/g, " ")
    .replace(/[\r\n]/g, " ")
    .trim()
    .slice(0, 500);

msg.payload = `${normalizeType(rawType)}\t${safeTitle}\t${safeMessage}`;
return msg;

function localDayKey(date) {
    return [
        date.getFullYear(),
        String(date.getMonth() + 1).padStart(2, '0'),
        String(date.getDate()).padStart(2, '0')
    ].join('-');
}

const result = msg.payload && msg.payload.result;
if (!result || typeof result !== 'object') {
    node.status({ fill: 'red', shape: 'ring', text: 'no forecast data' });
    return null;
}

const shadeByHour = {
    5: 0.02,
    6: 0.04,
    7: 0.06,
    8: 0.10,
    9: 0.18,
    10: 0.30,
    11: 0.55,
    12: 0.72,
    13: 0.78,
    14: 0.62,
    15: 0.50,
    16: 0.42,
    17: 0.32,
    18: 0.22,
    19: 0.14,
    20: 0.08,
    21: 0.03
};

const hourlyCapW = {
    5: 20,
    6: 40,
    7: 80,
    8: 150,
    9: 300,
    10: 550,
    11: 1100,
    12: 1500,
    13: 1500,
    14: 1200,
    15: 800,
    16: 700,
    17: 500,
    18: 320,
    19: 220,
    20: 140,
    21: 40
};

const historicalReference = {
    sunnyPeakKW: '1.4-1.5',
    cloudyPeakKW: '<1.0',
    dominantWindow: '11:00-17:00',
    extendedWindow: '05:00-21:00'
};

const resolution = Number(msg.resolution) || 1;
const periodHours = resolution > 0 ? 1 / resolution : 1;
const adjustedResult = {};
const summaryByDay = {};

for (const [key, rawValue] of Object.entries(result)) {
    const date = new Date(key);
    const hour = date.getHours();
    const factor = shadeByHour[hour] || 0;
    const shadedW = factor > 0 ? Math.round(Math.max(0, Number(rawValue) || 0) * factor) : 0;
    const capW = hourlyCapW[hour] || 0;
    const adjustedW = capW > 0 ? Math.min(shadedW, capW) : 0;
    const dayKey = localDayKey(date);

    adjustedResult[key] = adjustedW;

    if (!summaryByDay[dayKey]) {
        summaryByDay[dayKey] = {
            energyWh: 0,
            peakW: 0,
            activeHours: 0
        };
    }

    summaryByDay[dayKey].energyWh += adjustedW * periodHours;
    summaryByDay[dayKey].peakW = Math.max(summaryByDay[dayKey].peakW, adjustedW);
    if (adjustedW > 0) {
        summaryByDay[dayKey].activeHours += periodHours;
    }
}

const todayKey = localDayKey(new Date());
const today = summaryByDay[todayKey] || { energyWh: 0, peakW: 0, activeHours: 0 };
const todayKWh = +(today.energyWh / 1000).toFixed(2);
const todayPeakKW = +(today.peakW / 1000).toFixed(2);
const condition = todayPeakKW >= 1.0 ? 'sunny' : (todayKWh >= 2 ? 'cloudy' : 'low');

msg.topic = 'solar-forecast-adjusted';
msg.payload = {
    source: 'forecast.solar',
    location: 'Hokksund, Norway',
    activeWindow: '05:00-21:00',
    dominantWindow: '11:00-17:00',
    shading: 'trees / heavy shadow',
    rawResult: result,
    adjustedResult,
    summaryByDay,
    today: {
        energyWh: Math.round(today.energyWh),
        energyKWh: todayKWh,
        peakW: today.peakW,
        peakKW: todayPeakKW,
        activeHours: +today.activeHours.toFixed(2),
        condition
    },
    assumptions: {
        sunnyRangeKWh: '3-5',
        cloudyKWh: '2',
        shadeByHour,
        hourlyCapW,
        historicalReference
    }
};

node.status({ fill: 'blue', shape: 'dot', text: `${condition} | ${todayKWh}kWh | peak ${todayPeakKW}kW` });
return msg;

const data = msg.payload || {};
const today = data.today || { energyKWh: 0, peakKW: 0, condition: 'unknown' };
const summary = {
    updatedAt: new Date().toISOString(),
    source: data.source || 'forecast.solar',
    location: data.location || 'Hokksund, Norway',
    activeWindow: data.activeWindow || '11:00-17:00',
    condition: today.condition || 'unknown',
    energyWh: Number(today.energyWh) || 0,
    energyKWh: Number(today.energyKWh) || 0,
    peakW: Number(today.peakW) || 0,
    peakKW: Number(today.peakKW) || 0,
    activeHours: Number(today.activeHours) || 0
};

flow.set('solarForecastAdjusted', data);
flow.set('solarForecastToday', summary);

node.status({
    fill: summary.energyKWh > 0 ? 'green' : 'yellow',
    shape: 'dot',
    text: `${summary.condition} | ${summary.energyKWh.toFixed(2)}kWh | ${summary.activeWindow}`
});

msg.topic = 'solar-forecast-today';
msg.payload = summary;
return msg;

const rawMessage = (msg.notification && msg.notification.message) || (typeof msg.payload === 'string' ? msg.payload : null);
if (!rawMessage) return null;

const ts = (msg.notification && msg.notification.timestamp) || new Date().toISOString();
const logLine = ts + ' | ' + rawMessage + '\n';

const d = new Date();
const dateKey = [
    d.getFullYear(),
    String(d.getMonth() + 1).padStart(2, '0'),
    String(d.getDate()).padStart(2, '0')
].join('-');

const logDir = '/data/grid-control-logs';
msg.filename = logDir + '/grid-control-' + dateKey + '.log';
msg.payload = logLine;
msg.encoding = 'utf8';
return msg;

if (!msg.payload || !msg.payload.hourKey) return null;
const { hourKey, gridWh, acWh } = msg.payload;
const dateKey = hourKey.substring(0, 10);
const hourLabel = hourKey.substring(11, 13);
const line = dateKey + ' ' + hourLabel + ':00 | Grid ' + gridWh + 'Wh | AC ' + acWh + 'Wh\n';
msg.filename = '/data/grid-control-logs/energy-' + dateKey + '.log';
msg.payload = line;
msg.encoding = 'utf8';
return msg;

if (!msg.payload || !msg.payload.hourKey) return null;
const { hourKey, gridWh, acWh } = msg.payload;
const dateKey = hourKey.substring(0, 10);
const hourLabel = hourKey.substring(11, 13) + ':00';

let summary = flow.get('dailySummary') || { dateKey: '', hours: [] };
if (summary.dateKey !== dateKey) {
    summary = { dateKey, hours: [] };
}
summary.hours = summary.hours.filter(h => h.hour !== hourLabel);
summary.hours.push({ hour: hourLabel, gridWh, acWh });
summary.hours.sort((a, b) => a.hour.localeCompare(b.hour));
flow.set('dailySummary', summary);

const totalGrid = summary.hours.reduce((s, h) => s + h.gridWh, 0);
const totalAc   = summary.hours.reduce((s, h) => s + h.acWh, 0);
const lines = summary.hours.map(h => dateKey + ' ' + h.hour + ' | Grid ' + h.gridWh + 'Wh | AC ' + h.acWh + 'Wh');
lines.push('');
lines.push('TOTAL | Grid ' + totalGrid + 'Wh | AC ' + totalAc + 'Wh');

msg.payload  = lines.join('\n') + '\n';
msg.filename = '/data/grid-control-logs/summary-' + dateKey + '.log';
msg.encoding = 'utf8';
return msg;
